/**
 * MobileEditor Component
 * Form for creating and editing mobiles
 */

import React, { useState, useEffect } from 'react';
import useWorldBuilderStore from '../store/store';
import '../styles/EntityEditor.css';

export default function MobileEditor({ mobile, onSave, onCancel }) {
  const [formData, setFormData] = useState({
    vnum: '',
    keywords: '',
    short: '',
    long: '',
    race: '',
    description: '',
    level: 1,
    hp: 10,
    ac: 10,
  });
  const [isEditing, setIsEditing] = useState(!mobile);

  useEffect(() => {
    if (mobile) {
      setFormData({
        vnum: mobile.vnum || '',
        keywords: mobile.keywords || '',
        short: mobile.short || '',
        long: mobile.long || '',
        race: mobile.race || '',
        description: mobile.description || '',
        level: mobile.level || 1,
        hp: mobile.hp || 10,
        ac: mobile.ac || 10,
      });
      setIsEditing(false);
    } else {
      setIsEditing(true);
    }
  }, [mobile]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name.match(/^(level|hp|ac)$/) ? parseInt(value) || 0 : value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSave(formData);
    if (!mobile) {
      setFormData({
        vnum: '',
        keywords: '',
        short: '',
        long: '',
        race: '',
        description: '',
        level: 1,
        hp: 10,
        ac: 10,
      });
    }
  };

  if (!mobile && !isEditing) {
    return (
      <div className="entity-editor">
        <div className="editor-empty">
          <p>Select a mobile to edit or create a new one</p>
          <button className="btn-primary" onClick={() => setIsEditing(true)}>
            + Create New Mobile
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="entity-editor">
      <div className="editor-header">
        <h3>{mobile ? `Mobile ${mobile.vnum}` : 'New Mobile'}</h3>
        {!isEditing && (
          <button className="btn-secondary" onClick={() => setIsEditing(true)}>
            Edit
          </button>
        )}
      </div>

      {isEditing ? (
        <form onSubmit={handleSubmit} className="editor-form">
          <div className="form-group">
            <label htmlFor="vnum">VNUM *</label>
            <input
              id="vnum"
              type="number"
              name="vnum"
              value={formData.vnum}
              onChange={handleChange}
              required
              disabled={!!mobile}
            />
          </div>

          <div className="form-group">
            <label htmlFor="keywords">Keywords *</label>
            <input
              id="keywords"
              type="text"
              name="keywords"
              value={formData.keywords}
              onChange={handleChange}
              placeholder="e.g., 'gnome warrior' (space-separated)"
              required
            />
          </div>

          <div className="form-group">
            <label htmlFor="short">Short Description *</label>
            <input
              id="short"
              type="text"
              name="short"
              value={formData.short}
              onChange={handleChange}
              placeholder="e.g., 'a gnome warrior'"
              required
            />
          </div>

          <div className="form-group">
            <label htmlFor="long">Long Description</label>
            <textarea
              id="long"
              name="long"
              value={formData.long}
              onChange={handleChange}
              placeholder="Shown when examining the mobile"
              rows="4"
            />
          </div>

          <div className="form-group">
            <label htmlFor="race">Race</label>
            <select
              id="race"
              name="race"
              value={formData.race}
              onChange={handleChange}
            >
              <option value="">-- Select Race --</option>
              <option value="human">Human</option>
              <option value="elf">Elf</option>
              <option value="dwarf">Dwarf</option>
              <option value="gnome">Gnome</option>
              <option value="orc">Orc</option>
              <option value="undead">Undead</option>
              <option value="animal">Animal</option>
              <option value="demon">Demon</option>
            </select>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label htmlFor="level">Level</label>
              <input
                id="level"
                type="number"
                name="level"
                value={formData.level}
                onChange={handleChange}
                min="1"
              />
            </div>
            <div className="form-group">
              <label htmlFor="hp">Hit Points</label>
              <input
                id="hp"
                type="number"
                name="hp"
                value={formData.hp}
                onChange={handleChange}
                min="1"
              />
            </div>
            <div className="form-group">
              <label htmlFor="ac">Armor Class</label>
              <input
                id="ac"
                type="number"
                name="ac"
                value={formData.ac}
                onChange={handleChange}
              />
            </div>
          </div>

          <div className="form-group">
            <label htmlFor="description">Description</label>
            <textarea
              id="description"
              name="description"
              value={formData.description}
              onChange={handleChange}
              placeholder="Internal notes"
              rows="3"
            />
          </div>

          <div className="form-actions">
            <button type="submit" className="btn-primary">
              {mobile ? 'Update' : 'Create'}
            </button>
            <button
              type="button"
              className="btn-secondary"
              onClick={() => {
                if (mobile) {
                  setIsEditing(false);
                } else {
                  onCancel();
                }
              }}
            >
              Cancel
            </button>
          </div>
        </form>
      ) : (
        <div className="editor-view">
          <div className="view-field">
            <strong>VNUM:</strong> {formData.vnum}
          </div>
          <div className="view-field">
            <strong>Keywords:</strong> {formData.keywords}
          </div>
          <div className="view-field">
            <strong>Short:</strong> {formData.short}
          </div>
          {formData.long && (
            <div className="view-field">
              <strong>Long:</strong>
              <pre>{formData.long}</pre>
            </div>
          )}
          {formData.race && (
            <div className="view-field">
              <strong>Race:</strong> {formData.race}
            </div>
          )}
          <div className="view-row">
            <div className="view-field">
              <strong>Level:</strong> {formData.level}
            </div>
            <div className="view-field">
              <strong>HP:</strong> {formData.hp}
            </div>
            <div className="view-field">
              <strong>AC:</strong> {formData.ac}
            </div>
          </div>
          {formData.description && (
            <div className="view-field">
              <strong>Notes:</strong> {formData.description}
            </div>
          )}
        </div>
      )}
    </div>
  );
}
